_alloc:
    push rbp
    lea rbp, [rsp + 8]
    push r10
    push r11
    push r12
    push r13
    push r14
    push r15 ; scope init

    mov r10, rax ; (SET)
    mov rax, rsp ; User defined asm
    xor rdx, rdx ; User defined asm
    mov rcx, 16 ; User defined asm
    div rcx ; User defined asm
    sub rsp, rdx ; User defined asm
    sub rsp, 128 ; User defined asm
